-- ============================================================
-- NEUROWELLNESS — SUPABASE DATABASE SETUP
-- Version: 2.0.0
-- Run this ENTIRE file in Supabase → SQL Editor → New Query
-- Run in ONE shot — do not split into parts
--
-- CHANGES FROM v1.0.0:
--   STEP 8  → prs_diseases        (NEW — 16 conditions with full data)
--   STEP 9  → prs_scales          (same structure, seeded with all 47 scales)
--   STEP 10 → prs_question_branches (NEW — branching/skip logic per question)
--   STEP 11 → prs_questions       (expanded fields, seeded with all ~641 questions)
--   STEP 12 → prs_disease_scales  (NEW — disease → scale battery mapping)
--   STEP 13 → assessment_permissions (unchanged)
--   STEP 14 → assessment_sessions (NEW field: disease_id)
--   STEP 15 → scale_scores        (RENAMED from assessment_scores — score per scale)
--   STEP 16 → assessment_responses (links to scale_scores)
--   STEP 17 → assessment_scores   (NEW — total score across all scales in a session)
--   STEP 18 → notifications       (unchanged)
--   STEP 19 → audit_logs          (unchanged)
-- ============================================================

-- ============================================================
-- STEP 1: EXTENSIONS
-- ============================================================
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
CREATE EXTENSION IF NOT EXISTS "pg_trgm";

-- ============================================================
-- STEP 2: ENUMS
-- ============================================================
DO $$ BEGIN
  CREATE TYPE user_role AS ENUM ('doctor', 'patient', 'admin');
EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DO $$ BEGIN
  CREATE TYPE doctor_availability AS ENUM ('available', 'limited', 'unavailable');
EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DO $$ BEGIN
  CREATE TYPE session_status AS ENUM ('scheduled', 'in_progress', 'completed', 'cancelled');
EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DO $$ BEGIN
  CREATE TYPE assessment_permission_status AS ENUM ('pending', 'granted', 'revoked', 'completed');
EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DO $$ BEGIN
  CREATE TYPE assessment_taken_by AS ENUM ('patient', 'doctor_on_behalf');
EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- ============================================================
-- STEP 3: PROFILES (extends auth.users)
-- ============================================================
CREATE TABLE IF NOT EXISTS profiles (
  id              UUID PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
  role            user_role NOT NULL,
  full_name       TEXT NOT NULL,
  email           TEXT NOT NULL,
  phone           TEXT,
  city            TEXT,
  state           TEXT,
  country         TEXT DEFAULT 'India',
  date_of_birth   DATE,
  gender          TEXT CHECK (gender IN ('male', 'female', 'other', 'prefer_not_to_say')),
  avatar_url      TEXT,
  is_active       BOOLEAN DEFAULT TRUE,
  created_at      TIMESTAMPTZ DEFAULT NOW(),
  updated_at      TIMESTAMPTZ DEFAULT NOW()
);

-- ============================================================
-- STEP 4: DOCTORS
-- ============================================================
CREATE TABLE IF NOT EXISTS doctors (
  id                    UUID PRIMARY KEY REFERENCES profiles(id) ON DELETE CASCADE,
  specialization        TEXT,
  license_number        TEXT UNIQUE,
  hospital_affiliation  TEXT,
  max_patients          INT DEFAULT 50,
  current_patient_count INT DEFAULT 0,
  availability          doctor_availability DEFAULT 'available',
  bio                   TEXT,
  years_of_experience   INT,
  created_at            TIMESTAMPTZ DEFAULT NOW(),
  updated_at            TIMESTAMPTZ DEFAULT NOW()
);

-- ============================================================
-- STEP 5: PATIENTS
-- ============================================================
CREATE TABLE IF NOT EXISTS patients (
  id                  UUID PRIMARY KEY REFERENCES profiles(id) ON DELETE CASCADE,
  assigned_doctor_id  UUID REFERENCES doctors(id) ON DELETE SET NULL,
  medical_history     TEXT,
  emergency_contact   TEXT,
  insurance_info      JSONB DEFAULT '{}',
  created_at          TIMESTAMPTZ DEFAULT NOW(),
  updated_at          TIMESTAMPTZ DEFAULT NOW()
);

-- ============================================================
-- STEP 6: DOCTOR-PATIENT ALLOCATION LOG
-- ============================================================
CREATE TABLE IF NOT EXISTS doctor_patient_allocations (
  id                UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  patient_id        UUID NOT NULL REFERENCES patients(id) ON DELETE CASCADE,
  doctor_id         UUID NOT NULL REFERENCES doctors(id) ON DELETE CASCADE,
  allocated_at      TIMESTAMPTZ DEFAULT NOW(),
  allocation_reason TEXT,  -- 'auto_city_load_balance' | 'manual'
  is_active         BOOLEAN DEFAULT TRUE,
  UNIQUE(patient_id, doctor_id)
);

-- ============================================================
-- STEP 7: CLINICAL SESSIONS
-- ============================================================
CREATE TABLE IF NOT EXISTS sessions (
  id            UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  doctor_id     UUID NOT NULL REFERENCES doctors(id) ON DELETE CASCADE,
  patient_id    UUID NOT NULL REFERENCES patients(id) ON DELETE CASCADE,
  status        session_status DEFAULT 'scheduled',
  scheduled_at  TIMESTAMPTZ,
  started_at    TIMESTAMPTZ,
  completed_at  TIMESTAMPTZ,
  notes         TEXT,
  session_type  TEXT DEFAULT 'assessment' CHECK (session_type IN ('assessment', 'followup', 'consultation')),
  created_at    TIMESTAMPTZ DEFAULT NOW(),
  updated_at    TIMESTAMPTZ DEFAULT NOW()
);

-- ============================================================
-- STEP 8: PRS DISEASES
-- 16 neurological conditions — seeded below with full data
-- ============================================================
CREATE TABLE IF NOT EXISTS prs_diseases (
  id            UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  disease_code  TEXT NOT NULL UNIQUE,  -- e.g. 'depression-anxiety'
  label         TEXT NOT NULL,          -- e.g. 'Depression/Anxiety'
  description   TEXT,
  is_active     BOOLEAN DEFAULT TRUE,
  display_order INT DEFAULT 0,
  created_at    TIMESTAMPTZ DEFAULT NOW()
);

-- ============================================================
-- STEP 9: PRS SCALES
-- 47 assessment instruments — seeded below with full data
-- ============================================================
CREATE TABLE IF NOT EXISTS prs_scales (
  id               UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  scale_code       TEXT NOT NULL UNIQUE,  -- e.g. 'GAD-7', 'PHQ-9'
  name             TEXT NOT NULL,
  short_name       TEXT NOT NULL,
  description      TEXT,
  category         TEXT,                   -- 'anxiety' | 'depression' | 'sleep' | 'pain' etc.
  version          TEXT DEFAULT '1.0',
  recall_period    TEXT,
  instructions     TEXT,
  estimated_time   TEXT,
  scoring_method   TEXT NOT NULL,          -- matches JS scoringType/scoringMethod values
  max_score        NUMERIC,
  min_score        NUMERIC DEFAULT 0,
  max_item_score   NUMERIC,
  total_items      INT,
  score_direction  TEXT DEFAULT 'higher_worse',  -- 'higher_worse' | 'higher_better'
  cutoff_score     NUMERIC,
  scoring_config   JSONB DEFAULT '{}',     -- subscales, domains, components, weights
  severity_bands   JSONB DEFAULT '[]',
  risk_rules       JSONB DEFAULT '[]',
  interpretation   JSONB DEFAULT '{}',
  is_active        BOOLEAN DEFAULT TRUE,
  created_at       TIMESTAMPTZ DEFAULT NOW(),
  updated_at       TIMESTAMPTZ DEFAULT NOW()
);

-- ============================================================
-- ============================================================
-- STEP 10: PRS QUESTION BRANCHES
-- Stores every branching / skip rule from the scale JSON files.
-- 27 rules across 4 scales: AUDIT, COMPASS-31, GAD-7, IBS-SSS, SLEEP-50
--
-- branch_type values:
--   show_if            → show target question only if trigger Q == value
--   show_if_any_scored → show target question if any earlier Q scored >= threshold
--   show_if_ref_gt     → show target question if referenced Q (by orig_id) > value
--   show_if_ref_present→ show target question if referenced Q (by orig_id) was answered
--   skip_to_question   → if trigger Q == value, jump forward to target_question_index
--   skip_to_end        → if trigger Q == value, end the scale immediately
--
-- trigger_question_index / trigger_question_orig_id:
--   The question whose answer controls the branch.
--   One of these will be set — index for COMPASS-31/GAD-7, orig_id for SLEEP-50/IBS-SSS.
--
-- trigger_operator: == | > | >= | present
-- trigger_value:    the answer value that fires the rule (as text)
--
-- target_question_index / target_question_orig_id:
--   The question being shown/hidden OR the destination of a skip.
--   NULL for skip_to_end (no target question, just ends).
-- ============================================================
CREATE TABLE IF NOT EXISTS prs_question_branches (
  id                       UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  scale_id                 UUID NOT NULL REFERENCES prs_scales(id) ON DELETE CASCADE,
  branch_type              TEXT NOT NULL,
  -- The question whose answer triggers the rule
  trigger_question_index   INT,             -- 0-based index within the scale
  trigger_question_orig_id TEXT,            -- original JSON id field e.g. 'SLEEP50_32'
  trigger_operator         TEXT NOT NULL,   -- '==' | '>' | '>=' | 'present'
  trigger_value            TEXT,            -- value that fires the rule e.g. '0', '1', '1'
  -- The question affected by the rule
  target_question_index    INT,             -- 0-based index of the shown/hidden/jumped-to Q
  target_question_orig_id  TEXT,            -- original JSON id field of the target Q
  -- Optional message shown to clinician when rule fires
  message                  TEXT,
  -- Full raw rule JSON for reference / engine fallback
  raw_rule                 JSONB DEFAULT '{}',
  display_order            INT DEFAULT 0,   -- ordering within the scale for engine processing
  created_at               TIMESTAMPTZ DEFAULT NOW()
);

-- STEP 11: PRS QUESTIONS
-- All questions, each linked to exactly one section
-- 5–50 questions per scale, ~680 questions total
-- ============================================================
CREATE TABLE IF NOT EXISTS prs_questions (
  id                UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  scale_id          UUID NOT NULL REFERENCES prs_scales(id) ON DELETE CASCADE,
  question_index    INT NOT NULL,          -- 0-based position within scale
  question_number   INT,                   -- 1-based display number
  original_id       TEXT,                  -- original JSON 'id' field e.g. 'FIQR_1'
  label             TEXT,                  -- short label e.g. 'Nervous/Anxious'
  question_text     TEXT,                  -- full question text
  question_type     TEXT NOT NULL DEFAULT 'likert',
  -- scoring flags
  is_required       BOOLEAN DEFAULT TRUE,
  scored_in_total   BOOLEAN DEFAULT TRUE,
  include_in_score  BOOLEAN DEFAULT TRUE,
  supplementary     BOOLEAN DEFAULT FALSE,
  is_critical       BOOLEAN DEFAULT FALSE,
  is_risk_item      BOOLEAN DEFAULT FALSE,
  reversed          BOOLEAN DEFAULT FALSE,  -- reverse-scored item
  -- numeric / slider config
  min_value         NUMERIC,
  max_value         NUMERIC,
  step_value        NUMERIC,
  unit              TEXT,
  placeholder       TEXT,
  -- VAS anchors
  left_anchor       TEXT,
  right_anchor      TEXT,
  -- answer options [{value, label, points, notApplicable, screeningPositive}]
  options           JSONB DEFAULT '[]',
  -- extra metadata
  instructions      TEXT,
  hint              TEXT,
  note              TEXT,
  scoring_note      TEXT,
  -- original section/domain/subscale reference strings (for engine use)
  section_ref       TEXT,
  subscale_ref      TEXT,
  domain_ref        TEXT,
  weight            NUMERIC,
  multiplier        NUMERIC,
  used_in_component INT,                   -- PSQI component number
  created_at        TIMESTAMPTZ DEFAULT NOW(),
  UNIQUE(scale_id, question_index)
);

-- ============================================================
-- STEP 12: PRS DISEASE-SCALES
-- Ordered mapping of which scales belong to each disease
-- 131 rows total (e.g. depression-anxiety uses 7 scales ordered 0–6)
-- ============================================================
CREATE TABLE IF NOT EXISTS prs_disease_scales (
  id            UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  disease_id    UUID NOT NULL REFERENCES prs_diseases(id) ON DELETE CASCADE,
  scale_id      UUID NOT NULL REFERENCES prs_scales(id) ON DELETE CASCADE,
  display_order INT NOT NULL DEFAULT 0,   -- order the scale appears in the battery
  is_required   BOOLEAN DEFAULT TRUE,
  created_at    TIMESTAMPTZ DEFAULT NOW(),
  UNIQUE(disease_id, scale_id)
);

-- ============================================================
-- STEP 13: ASSESSMENT PERMISSIONS
-- Doctor grants patient permission to take a specific scale
-- ============================================================
CREATE TABLE IF NOT EXISTS assessment_permissions (
  id            UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  patient_id    UUID NOT NULL REFERENCES patients(id) ON DELETE CASCADE,
  doctor_id     UUID NOT NULL REFERENCES doctors(id) ON DELETE CASCADE,
  disease_id    UUID REFERENCES prs_diseases(id) ON DELETE SET NULL,  -- which disease this permission is for
  scale_id      UUID NOT NULL REFERENCES prs_scales(id) ON DELETE CASCADE,
  session_id    UUID REFERENCES sessions(id) ON DELETE SET NULL,
  status        assessment_permission_status DEFAULT 'granted',
  granted_at    TIMESTAMPTZ DEFAULT NOW(),
  expires_at    TIMESTAMPTZ,
  revoked_at    TIMESTAMPTZ,
  notes         TEXT,
  UNIQUE(patient_id, scale_id, session_id)
);

-- ============================================================
-- STEP 14: ASSESSMENT SESSIONS
-- One row per full disease assessment attempt (covers all scales in that disease)
-- ============================================================
CREATE TABLE IF NOT EXISTS assessment_sessions (
  id            UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  patient_id    UUID NOT NULL REFERENCES patients(id) ON DELETE CASCADE,
  doctor_id     UUID NOT NULL REFERENCES doctors(id) ON DELETE CASCADE,
  disease_id    UUID NOT NULL REFERENCES prs_diseases(id) ON DELETE CASCADE,  -- which disease was assessed
  session_id    UUID REFERENCES sessions(id) ON DELETE SET NULL,
  taken_by      assessment_taken_by DEFAULT 'patient',
  status        TEXT DEFAULT 'in_progress' CHECK (status IN ('in_progress', 'completed', 'abandoned')),
  started_at    TIMESTAMPTZ DEFAULT NOW(),
  completed_at  TIMESTAMPTZ,
  created_at    TIMESTAMPTZ DEFAULT NOW()
);

-- ============================================================
-- STEP 15: SCALE SCORES
-- Computed score for ONE scale within an assessment session
-- One row per scale completed — many rows per assessment_session
-- (renamed from assessment_scores in v1)
-- ============================================================
CREATE TABLE IF NOT EXISTS scale_scores (
  id                    UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  assessment_session_id UUID NOT NULL REFERENCES assessment_sessions(id) ON DELETE CASCADE,
  patient_id            UUID NOT NULL REFERENCES patients(id) ON DELETE CASCADE,
  disease_id            UUID NOT NULL REFERENCES prs_diseases(id) ON DELETE CASCADE,
  scale_id              UUID NOT NULL REFERENCES prs_scales(id) ON DELETE CASCADE,
  total_score           NUMERIC,
  max_possible          NUMERIC,
  percentage            NUMERIC GENERATED ALWAYS AS (
    CASE WHEN max_possible > 0 THEN ROUND((total_score / max_possible) * 100, 2) ELSE NULL END
  ) STORED,
  severity_level        TEXT,      -- 'minimal' | 'mild' | 'moderate' | 'severe' etc.
  severity_label        TEXT,      -- human label e.g. 'Moderate Anxiety'
  subscale_scores       JSONB DEFAULT '{}',
  domain_scores         JSONB DEFAULT '{}',
  component_scores      JSONB DEFAULT '{}',
  question_scores       JSONB DEFAULT '{}',
  risk_flags            JSONB DEFAULT '[]',
  raw_score_data        JSONB DEFAULT '{}',  -- full output from scale engine
  calculated_at         TIMESTAMPTZ DEFAULT NOW(),
  UNIQUE(assessment_session_id, scale_id)   -- one score per scale per session
);

-- ============================================================
-- STEP 16: ASSESSMENT RESPONSES
-- Individual question answers — linked to a scale_score row
-- ============================================================
CREATE TABLE IF NOT EXISTS assessment_responses (
  id              UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  scale_score_id  UUID NOT NULL REFERENCES scale_scores(id) ON DELETE CASCADE,  -- see STEP 16
  question_id     UUID NOT NULL REFERENCES prs_questions(id) ON DELETE CASCADE,
  question_index  INT NOT NULL,
  response_value  TEXT,
  response_label  TEXT,
  created_at      TIMESTAMPTZ DEFAULT NOW(),
  UNIQUE(scale_score_id, question_index)
);

-- ============================================================
-- STEP 17: ASSESSMENT SCORES
-- Aggregated total score across ALL scales in an assessment session
-- One row per completed assessment_session
-- ============================================================
CREATE TABLE IF NOT EXISTS assessment_scores (
  id                    UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  assessment_session_id UUID NOT NULL UNIQUE REFERENCES assessment_sessions(id) ON DELETE CASCADE,
  patient_id            UUID NOT NULL REFERENCES patients(id) ON DELETE CASCADE,
  disease_id            UUID NOT NULL REFERENCES prs_diseases(id) ON DELETE CASCADE,
  -- Aggregate numbers across all scale_scores for this session
  total_score           NUMERIC,       -- sum of all scale total_scores
  max_possible          NUMERIC,       -- sum of all scale max_possibles
  percentage            NUMERIC GENERATED ALWAYS AS (
    CASE WHEN max_possible > 0 THEN ROUND((total_score / max_possible) * 100, 2) ELSE NULL END
  ) STORED,
  scales_completed      INT DEFAULT 0,  -- how many scales were finished
  scales_total          INT DEFAULT 0,  -- total scales in the disease battery
  overall_severity      TEXT,            -- derived from most impaired scale
  overall_severity_label TEXT,
  -- Per-scale summary snapshot [{scale_code, scale_name, score, max, severity_level, severity_label}]
  scale_summaries       JSONB DEFAULT '[]',
  -- All risk flags collected across all scales
  all_risk_flags        JSONB DEFAULT '[]',
  composite_summary     TEXT,            -- narrative summary text
  calculated_at         TIMESTAMPTZ DEFAULT NOW()
);

-- ============================================================
-- STEP 18: NOTIFICATIONS
-- ============================================================
CREATE TABLE IF NOT EXISTS notifications (
  id          UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  user_id     UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,
  type        TEXT NOT NULL,  -- 'permission_granted' | 'assessment_completed' | 'session_scheduled'
  title       TEXT NOT NULL,
  body        TEXT,
  data        JSONB DEFAULT '{}',
  is_read     BOOLEAN DEFAULT FALSE,
  created_at  TIMESTAMPTZ DEFAULT NOW()
);

-- ============================================================
-- STEP 19: AUDIT LOGS
-- ============================================================
CREATE TABLE IF NOT EXISTS audit_logs (
  id            UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  user_id       UUID REFERENCES profiles(id) ON DELETE SET NULL,
  action        TEXT NOT NULL,
  resource_type TEXT,
  resource_id   UUID,
  old_data      JSONB,
  new_data      JSONB,
  ip_address    TEXT,
  user_agent    TEXT,
  created_at    TIMESTAMPTZ DEFAULT NOW()
);

-- ============================================================
-- STEP 20: PERFORMANCE INDEXES
-- ============================================================
CREATE INDEX IF NOT EXISTS idx_profiles_city               ON profiles USING gin(city gin_trgm_ops);
CREATE INDEX IF NOT EXISTS idx_profiles_role               ON profiles(role);
CREATE INDEX IF NOT EXISTS idx_patients_doctor             ON patients(assigned_doctor_id);
CREATE INDEX IF NOT EXISTS idx_sessions_doctor             ON sessions(doctor_id);
CREATE INDEX IF NOT EXISTS idx_sessions_patient            ON sessions(patient_id);
CREATE INDEX IF NOT EXISTS idx_sessions_status             ON sessions(status);
CREATE INDEX IF NOT EXISTS idx_assessment_sessions_patient ON assessment_sessions(patient_id);
CREATE INDEX IF NOT EXISTS idx_assessment_sessions_disease ON assessment_sessions(disease_id);
CREATE INDEX IF NOT EXISTS idx_assessment_sessions_status  ON assessment_sessions(status);
CREATE INDEX IF NOT EXISTS idx_assessment_permissions_patient ON assessment_permissions(patient_id);
CREATE INDEX IF NOT EXISTS idx_assessment_permissions_doctor  ON assessment_permissions(doctor_id);
CREATE INDEX IF NOT EXISTS idx_assessment_permissions_status  ON assessment_permissions(status);
CREATE INDEX IF NOT EXISTS idx_scale_scores_session        ON scale_scores(assessment_session_id);
CREATE INDEX IF NOT EXISTS idx_scale_scores_patient        ON scale_scores(patient_id);
CREATE INDEX IF NOT EXISTS idx_scale_scores_scale          ON scale_scores(scale_id);
CREATE INDEX IF NOT EXISTS idx_scale_scores_disease        ON scale_scores(disease_id);
CREATE INDEX IF NOT EXISTS idx_assessment_scores_patient   ON assessment_scores(patient_id);
CREATE INDEX IF NOT EXISTS idx_assessment_scores_disease   ON assessment_scores(disease_id);
CREATE INDEX IF NOT EXISTS idx_notifications_user          ON notifications(user_id, is_read);
CREATE INDEX IF NOT EXISTS idx_notifications_created       ON notifications(created_at DESC);
CREATE INDEX IF NOT EXISTS idx_audit_logs_user             ON audit_logs(user_id, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_prs_diseases_active         ON prs_diseases(is_active);
CREATE INDEX IF NOT EXISTS idx_prs_scales_active           ON prs_scales(is_active);
CREATE INDEX IF NOT EXISTS idx_prs_branches_scale          ON prs_question_branches(scale_id);
CREATE INDEX IF NOT EXISTS idx_prs_branches_trigger        ON prs_question_branches(scale_id, trigger_question_index);
CREATE INDEX IF NOT EXISTS idx_prs_branches_target         ON prs_question_branches(scale_id, target_question_index);
CREATE INDEX IF NOT EXISTS idx_prs_questions_scale         ON prs_questions(scale_id);
CREATE INDEX IF NOT EXISTS idx_prs_questions_index         ON prs_questions(scale_id, question_index);
CREATE INDEX IF NOT EXISTS idx_prs_disease_scales_disease  ON prs_disease_scales(disease_id);
CREATE INDEX IF NOT EXISTS idx_prs_disease_scales_scale    ON prs_disease_scales(scale_id);

-- ============================================================
-- STEP 21: TRIGGERS — auto updated_at
-- ============================================================
CREATE OR REPLACE FUNCTION update_updated_at_column()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_profiles_updated_at ON profiles;
CREATE TRIGGER trg_profiles_updated_at
  BEFORE UPDATE ON profiles FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

DROP TRIGGER IF EXISTS trg_doctors_updated_at ON doctors;
CREATE TRIGGER trg_doctors_updated_at
  BEFORE UPDATE ON doctors FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

DROP TRIGGER IF EXISTS trg_patients_updated_at ON patients;
CREATE TRIGGER trg_patients_updated_at
  BEFORE UPDATE ON patients FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

DROP TRIGGER IF EXISTS trg_sessions_updated_at ON sessions;
CREATE TRIGGER trg_sessions_updated_at
  BEFORE UPDATE ON sessions FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

DROP TRIGGER IF EXISTS trg_prs_scales_updated_at ON prs_scales;
CREATE TRIGGER trg_prs_scales_updated_at
  BEFORE UPDATE ON prs_scales FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

-- ============================================================
-- STEP 22: DOCTOR PATIENT COUNT SYNC TRIGGER
-- ============================================================
CREATE OR REPLACE FUNCTION sync_doctor_patient_count()
RETURNS TRIGGER AS $$
BEGIN
  IF NEW.assigned_doctor_id IS NOT NULL THEN
    UPDATE doctors SET current_patient_count = (
      SELECT COUNT(*) FROM patients WHERE assigned_doctor_id = NEW.assigned_doctor_id
    ) WHERE id = NEW.assigned_doctor_id;
  END IF;
  IF OLD.assigned_doctor_id IS NOT NULL AND OLD.assigned_doctor_id IS DISTINCT FROM NEW.assigned_doctor_id THEN
    UPDATE doctors SET current_patient_count = (
      SELECT COUNT(*) FROM patients WHERE assigned_doctor_id = OLD.assigned_doctor_id
    ) WHERE id = OLD.assigned_doctor_id;
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_sync_patient_count ON patients;
CREATE TRIGGER trg_sync_patient_count
  AFTER INSERT OR UPDATE OF assigned_doctor_id ON patients
  FOR EACH ROW EXECUTE FUNCTION sync_doctor_patient_count();

-- ============================================================
-- STEP 23: AUTO-CALCULATE ASSESSMENT SCORES TRIGGER
-- When all scale_scores for a session are in, compute the total
-- ============================================================
CREATE OR REPLACE FUNCTION recalculate_assessment_score()
RETURNS TRIGGER AS $$
DECLARE
  v_session     assessment_sessions%ROWTYPE;
  v_total       NUMERIC := 0;
  v_max         NUMERIC := 0;
  v_completed   INT := 0;
  v_total_scales INT := 0;
  v_worst_sev   TEXT := NULL;
  v_worst_label TEXT := NULL;
  v_summaries   JSONB := '[]'::jsonb;
  v_all_flags   JSONB := '[]'::jsonb;
  sev_order     INT;
  worst_order   INT := -1;
  r             RECORD;
BEGIN
  SELECT * INTO v_session FROM assessment_sessions WHERE id = NEW.assessment_session_id;

  -- Count total scales for this disease
  SELECT COUNT(*) INTO v_total_scales
  FROM prs_disease_scales ds
  JOIN prs_diseases d ON d.id = ds.disease_id
  WHERE ds.disease_id = v_session.disease_id;

  -- Aggregate all scale_scores for this session
  FOR r IN
    SELECT ss.*, sc.scale_code, sc.name AS scale_name
    FROM scale_scores ss
    JOIN prs_scales sc ON sc.id = ss.scale_id
    WHERE ss.assessment_session_id = NEW.assessment_session_id
  LOOP
    v_total     := v_total + COALESCE(r.total_score, 0);
    v_max       := v_max   + COALESCE(r.max_possible, 0);
    v_completed := v_completed + 1;

    -- Track worst severity level
    sev_order := CASE r.severity_level
      WHEN 'severe'            THEN 4
      WHEN 'moderately-severe' THEN 3
      WHEN 'moderate'          THEN 2
      WHEN 'mild'              THEN 1
      ELSE 0
    END;
    IF sev_order > worst_order THEN
      worst_order   := sev_order;
      v_worst_sev   := r.severity_level;
      v_worst_label := r.severity_label;
    END IF;

    -- Build per-scale summary snapshot
    v_summaries := v_summaries || jsonb_build_object(
      'scale_code',     r.scale_code,
      'scale_name',     r.scale_name,
      'score',          r.total_score,
      'max_possible',   r.max_possible,
      'percentage',     CASE WHEN r.max_possible > 0 THEN ROUND((r.total_score / r.max_possible) * 100, 2) ELSE NULL END,
      'severity_level', r.severity_level,
      'severity_label', r.severity_label
    );

    -- Collect all risk flags
    IF r.risk_flags IS NOT NULL AND jsonb_array_length(r.risk_flags) > 0 THEN
      v_all_flags := v_all_flags || r.risk_flags;
    END IF;
  END LOOP;

  -- Upsert into assessment_scores
  INSERT INTO assessment_scores (
    assessment_session_id, patient_id, disease_id,
    total_score, max_possible, scales_completed, scales_total,
    overall_severity, overall_severity_label,
    scale_summaries, all_risk_flags, calculated_at
  ) VALUES (
    NEW.assessment_session_id, v_session.patient_id, v_session.disease_id,
    v_total, v_max, v_completed, v_total_scales,
    v_worst_sev, v_worst_label,
    v_summaries, v_all_flags, NOW()
  )
  ON CONFLICT (assessment_session_id) DO UPDATE SET
    total_score           = EXCLUDED.total_score,
    max_possible          = EXCLUDED.max_possible,
    scales_completed      = EXCLUDED.scales_completed,
    scales_total          = EXCLUDED.scales_total,
    overall_severity      = EXCLUDED.overall_severity,
    overall_severity_label= EXCLUDED.overall_severity_label,
    scale_summaries       = EXCLUDED.scale_summaries,
    all_risk_flags        = EXCLUDED.all_risk_flags,
    calculated_at         = NOW();

  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_recalculate_assessment_score ON scale_scores;
CREATE TRIGGER trg_recalculate_assessment_score
  AFTER INSERT OR UPDATE ON scale_scores
  FOR EACH ROW EXECUTE FUNCTION recalculate_assessment_score();

-- ============================================================
-- STEP 24: DOCTOR ALLOCATION FUNCTION
-- Priority: same city + fewest patients → any available + fewest patients
-- ============================================================
CREATE OR REPLACE FUNCTION allocate_doctor_to_patient(
  p_patient_id UUID,
  p_city TEXT DEFAULT NULL
)
RETURNS UUID AS $$
DECLARE
  v_doctor_id UUID;
BEGIN
  IF p_city IS NOT NULL THEN
    SELECT d.id INTO v_doctor_id
    FROM doctors d
    JOIN profiles p ON p.id = d.id
    WHERE LOWER(p.city) = LOWER(p_city)
      AND d.availability = 'available'
      AND d.current_patient_count < d.max_patients
    ORDER BY d.current_patient_count ASC, d.created_at ASC
    LIMIT 1;
  END IF;

  IF v_doctor_id IS NULL THEN
    SELECT id INTO v_doctor_id
    FROM doctors
    WHERE availability = 'available'
      AND current_patient_count < max_patients
    ORDER BY current_patient_count ASC, created_at ASC
    LIMIT 1;
  END IF;

  IF v_doctor_id IS NOT NULL THEN
    UPDATE patients SET assigned_doctor_id = v_doctor_id WHERE id = p_patient_id;
    INSERT INTO doctor_patient_allocations(patient_id, doctor_id, allocation_reason)
    VALUES (p_patient_id, v_doctor_id, 'auto_city_load_balance')
    ON CONFLICT (patient_id, doctor_id) DO NOTHING;
  END IF;

  RETURN v_doctor_id;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

