-- PROFILES
CREATE POLICY "profiles_insert_own" ON profiles FOR INSERT
  WITH CHECK (auth.uid() = id);
CREATE POLICY "profiles_self_read" ON profiles FOR SELECT
  USING (auth.uid() = id);
CREATE POLICY "profiles_self_update" ON profiles FOR UPDATE
  USING (auth.uid() = id);
CREATE POLICY "profiles_doctor_read_patients" ON profiles FOR SELECT
  USING (
    EXISTS (
      SELECT 1 FROM patients p
      WHERE p.id = profiles.id AND p.assigned_doctor_id = auth.uid()
    )
  );

-- DOCTORS
CREATE POLICY "doctors_self_read" ON doctors FOR SELECT
  USING (auth.uid() = id);
CREATE POLICY "doctors_self_update" ON doctors FOR UPDATE
  USING (auth.uid() = id);
CREATE POLICY "doctors_patient_read_assigned" ON doctors FOR SELECT
  USING (
    EXISTS (
      SELECT 1 FROM patients p
      WHERE p.id = auth.uid() AND p.assigned_doctor_id = doctors.id
    )
  );

-- PATIENTS
CREATE POLICY "patients_self_read" ON patients FOR SELECT
  USING (auth.uid() = id);
CREATE POLICY "patients_self_update" ON patients FOR UPDATE
  USING (auth.uid() = id);
CREATE POLICY "patients_doctor_read" ON patients FOR SELECT
  USING (assigned_doctor_id = auth.uid());

-- SESSIONS
CREATE POLICY "sessions_doctor_all" ON sessions FOR ALL
  USING (doctor_id = auth.uid());
CREATE POLICY "sessions_patient_read" ON sessions FOR SELECT
  USING (patient_id = auth.uid());

-- ASSESSMENT PERMISSIONS
CREATE POLICY "permissions_doctor_all" ON assessment_permissions FOR ALL
  USING (doctor_id = auth.uid());
CREATE POLICY "permissions_patient_read" ON assessment_permissions FOR SELECT
  USING (patient_id = auth.uid());

-- ASSESSMENT SESSIONS
CREATE POLICY "assessment_sessions_own" ON assessment_sessions FOR ALL
  USING (patient_id = auth.uid());
CREATE POLICY "assessment_sessions_doctor" ON assessment_sessions FOR ALL
  USING (doctor_id = auth.uid());

-- ASSESSMENT RESPONSES — doctor reads all; patient/doctor inserts
CREATE POLICY "assessment_responses_doctor_read" ON assessment_responses FOR SELECT
  USING (
    EXISTS (
      SELECT 1 FROM scale_scores ss
      JOIN assessment_sessions ases ON ases.id = ss.assessment_session_id
      WHERE ss.id = assessment_responses.scale_score_id
        AND ases.doctor_id = auth.uid()
    )
  );
CREATE POLICY "assessment_responses_insert_own" ON assessment_responses FOR INSERT
  WITH CHECK (
    EXISTS (
      SELECT 1 FROM scale_scores ss
      JOIN assessment_sessions ases ON ases.id = ss.assessment_session_id
      WHERE ss.id = assessment_responses.scale_score_id
        AND (ases.patient_id = auth.uid() OR ases.doctor_id = auth.uid())
    )
  );

-- SCALE SCORES — patient sees own score only (no responses); doctor sees their patients'
CREATE POLICY "scale_scores_patient_own" ON scale_scores FOR SELECT
  USING (patient_id = auth.uid());
CREATE POLICY "scale_scores_doctor_read" ON scale_scores FOR SELECT
  USING (
    EXISTS (
      SELECT 1 FROM patients p
      WHERE p.id = scale_scores.patient_id AND p.assigned_doctor_id = auth.uid()
    )
  );

-- ASSESSMENT SCORES (totals) — same visibility rules
CREATE POLICY "assessment_scores_patient_own" ON assessment_scores FOR SELECT
  USING (patient_id = auth.uid());
CREATE POLICY "assessment_scores_doctor_read" ON assessment_scores FOR SELECT
  USING (
    EXISTS (
      SELECT 1 FROM patients p
      WHERE p.id = assessment_scores.patient_id AND p.assigned_doctor_id = auth.uid()
    )
  );

-- NOTIFICATIONS — own only
CREATE POLICY "notifications_own" ON notifications FOR ALL
  USING (user_id = auth.uid());

-- PRS REFERENCE TABLES — read-only for all authenticated users
CREATE POLICY "prs_diseases_read"       ON prs_diseases       FOR SELECT USING (auth.role() = 'authenticated');
CREATE POLICY "prs_scales_read"         ON prs_scales         FOR SELECT USING (auth.role() = 'authenticated');
CREATE POLICY "prs_branches_read"       ON prs_question_branches FOR SELECT USING (auth.role() = 'authenticated');
CREATE POLICY "prs_questions_read"      ON prs_questions      FOR SELECT USING (auth.role() = 'authenticated');
CREATE POLICY "prs_disease_scales_read" ON prs_disease_scales FOR SELECT USING (auth.role() = 'authenticated');

