DECLARE
  v_scale_id UUID;
BEGIN

  -- Scale
  INSERT INTO prs_scales (
    scale_code, name, short_name, description, category, version,
    recall_period, instructions, estimated_time, scoring_method,
    max_score, min_score, max_item_score, total_items, score_direction,
    cutoff_score, scoring_config, severity_bands, risk_rules, interpretation)
  VALUES (
    'DHI', 'Dizziness Handicap Inventory', 'DHI',
    'A self-assessment questionnaire designed to evaluate the self-perceived handicapping effects of dizziness on daily life, incorporating functional, physical, and emotional impacts.', 'vestibular', '1.0',
    'During the last month', 'Please answer each question as it pertains to your dizziness or unsteadiness problems. Consider your condition during the last month.',
    '5-10 minutes', 'sum',
    100.0, 0.0, NULL,
    25.0, 'higher_worse',
    10.0,
    '{"domains": {"physical": {"name": "Physical", "items": [0, 3, 7, 10, 12, 16, 24], "maxScore": 28, "description": "Physical aspects of dizziness triggered by movements or positions"}, "emotional": {"name": "Emotional", "items": [1, 8, 9, 14, 17, 19, 20, 21, 22], "maxScore": 36, "description": "Emotional consequences of dizziness"}, "functional": {"name": "Functional", "items": [2, 4, 5, 6, 11, 13, 15, 18, 23], "maxScore": 36, "description": "Functional limitations in daily activities due to dizziness"}}, "cutoff": 10}'::jsonb, '[{"id": "no-handicap", "label": "No Handicap", "min": 0, "max": 10, "color": "#22c55e", "description": "No significant dizziness-related handicap."}, {"id": "mild", "label": "Mild Handicap", "min": 11, "max": 34, "color": "#eab308", "description": "Mild dizziness-related handicap; balance specialist referral may be warranted."}, {"id": "moderate", "label": "Moderate Handicap", "min": 35, "max": 52, "color": "#f97316", "description": "Moderate dizziness-related handicap affecting daily activities."}, {"id": "severe", "label": "Severe Handicap", "min": 53, "max": 100, "color": "#ef4444", "description": "Severe dizziness-related handicap with significant functional impairment."}]'::jsonb,
    '[]'::jsonb, '{"scoringMethod": "Sum all items. No=0, Sometimes=2, Yes=4. Range: 0-100.", "referralThreshold": "Scores greater than 10 points should be referred to balance specialists for further evaluation.", "subscaleScoring": "Physical (7 items, max 28), Emotional (9 items, max 36), Functional (9 items, max 36)", "clinicalNotes": "The DHI provides both a total score and subscale scores to help identify the nature of the patient''s dizziness-related difficulties."}'::jsonb)
  ON CONFLICT (scale_code) DO UPDATE SET
