    cutoff_score, scoring_config, severity_bands, risk_rules, interpretation)
  VALUES (
    'FSS', 'Fatigue Severity Scale', 'FSS',
    'A 9-item self-report questionnaire that measures the severity of fatigue and its effect on a person''s activities and lifestyle. Widely used in neurological conditions including multiple sclerosis, lupus, and chronic fatigue syndrome.', 'fatigue', '1.0',
    'During the past week', 'Read each statement and select a number from 1 to 7, depending on how appropriate the statement applies to you over the preceding week. A low value (1) indicates strong disagreement, a high value (7) indicates strong agreement.',
    '3-5 minutes', 'mean',
    7.0, 1.0, NULL,
    9.0, 'higher_worse',
    NULL,
    '{}'::jsonb, '[{"id": "no-fatigue", "label": "No Significant Fatigue", "range": {"min": 1.0, "max": 2.9}, "color": "#22c55e", "description": "No clinically significant fatigue."}, {"id": "mild", "label": "Mild Fatigue", "range": {"min": 3.0, "max": 3.9}, "color": "#84cc16", "description": "Borderline fatigue, may warrant monitoring."}, {"id": "moderate", "label": "Moderate Fatigue", "range": {"min": 4.0, "max": 4.9}, "color": "#eab308", "description": "Clinically significant fatigue present."}, {"id": "severe", "label": "Severe Fatigue", "range": {"min": 5.0, "max": 7.0}, "color": "#dc2626", "description": "Severe fatigue significantly impacting daily functioning."}]'::jsonb,
    '[]'::jsonb, '{"scoringMethod": "Calculate the mean of all 9 responses (sum of scores \u00f7 9). Score range: 1-7.", "clinicalCutoff": "A mean score \u22654 indicates clinically significant fatigue.", "populationNorms": "Healthy adults typically score 2-3. Patients with chronic conditions often score 4-6.", "clinicalUse": "Widely used in multiple sclerosis, systemic lupus erythematosus, chronic fatigue syndrome, Parkinson''s disease, and other conditions associated with fatigue.", "minimumClinicallyImportantDifference": "A change of 0.5-1.0 points in mean score is generally considered clinically meaningful."}'::jsonb)
  ON CONFLICT (scale_code) DO UPDATE SET
