  VALUES (
    'LANSS', 'Leeds Assessment of Neuropathic Symptoms and Signs', 'LANSS',
    'A pain scale to determine whether nerves carrying pain signals are working normally, helping identify neuropathic pain mechanisms', NULL, '1.0',
    'Over the last week', 'This pain scale can help to determine whether the nerves that are carrying your pain signals are working normally or not. It is important to find this out in case different treatments are needed to control your pain.',
    NULL, 'weighted-sum',
    24.0, 0.0, NULL,
    7.0, 'higher_worse',
    12.0,
    '{"scoringWeights": {"painQuestionnaire": {"q1_dysesthesia": {"no": 0, "yes": 5}, "q2_skin_color": {"no": 0, "yes": 5}, "q3_touch_sensitivity": {"no": 0, "yes": 3}, "q4_sudden_bursts": {"no": 0, "yes": 2}, "q5_temperature": {"no": 0, "yes": 1}}, "sensoryTesting": {"allodynia": {"no": 0, "yes": 5}, "altered_ppt": {"no": 0, "yes": 3}}, "maxPartA": 16, "maxPartB": 8, "maxTotal": 24}, "cutoffScore": 12}'::jsonb, '[{"min": 0, "max": 11, "level": "nociceptive", "label": "Nociceptive Pain Likely", "description": "Neuropathic mechanisms are unlikely to be contributing to the patient''s pain. Pain is likely nociceptive in origin."}, {"min": 12, "max": 24, "level": "neuropathic", "label": "Neuropathic Pain Likely", "description": "Neuropathic mechanisms are likely to be contributing to the patient''s pain. Consider treatments targeting neuropathic pain."}]'::jsonb,
    '[{"type": "total_score", "operator": ">=", "threshold": 12, "severity": "moderate", "message": "LANSS score \u2265 12 indicates neuropathic pain mechanisms are likely contributing. Consider neuropathic pain treatments (anticonvulsants, antidepressants, topical agents)."}, {"type": "symptom_pattern", "questionIndices": [0, 3], "condition": "both_positive", "severity": "moderate", "message": "Presence of dysesthesia and spontaneous pain episodes suggests significant neuropathic component"}, {"type": "clinical_finding", "questionIndex": 5, "operator": "==", "threshold": 5, "severity": "moderate", "message": "Allodynia detected on clinical examination - key indicator of central sensitization"}]'::jsonb, '{"clinicalNotes": "The LANSS Pain Scale combines self-reported symptoms (Part A) with bedside sensory testing (Part B) to identify pain of predominantly neuropathic origin. A score of 12 or more suggests neuropathic mechanisms are likely contributing to the patient''s pain.", "cutoffExplanation": {"threshold": 12, "sensitivity": "85%", "specificity": "80%", "description": "A cutoff of \u226512 provides good discrimination between nociceptive and neuropathic pain. The scale correctly identifies neuropathic pain in approximately 85% of cases."}, "symptomDescriptors": {"dysesthesia": "Strange, unpleasant sensations (pricking, tingling, pins and needles)", "autonomic_changes": "Skin color changes (mottled, red, pink appearance)", "allodynia": "Abnormal sensitivity to touch, pain from light stroking or tight clothes", "paroxysmal_pain": "Sudden bursts of pain (electric shocks, jumping, bursting)", "thermal_sensations": "Abnormal temperature sensations (hot, burning)"}, "sensoryTestingNotes": {"allodynia_test": "Compare response to cotton wool stroking between painful and non-painful areas. Allodynia present if pain/unpleasant sensation occurs only in painful area.", "ppt_test": "Use 23-gauge needle in 2ml syringe barrel. Compare pin-prick sensation between areas. Altered PPT if sensation differs (blunted or hyperalgesic) in painful area.", "equipment": "Cotton wool, 23-gauge (blue) needle, 2ml syringe barrel"}, "treatmentImplications": {"nociceptive": "Standard analgesics (NSAIDs, paracetamol, opioids) may be effective", "neuropathic": "Consider first-line neuropathic agents: gabapentinoids (pregabalin, gabapentin), SNRIs (duloxetine, venlafaxine), TCAs (amitriptyline). Topical lidocaine or capsaicin for localized pain. Standard analgesics often less effective alone."}, "actions": {"nociceptive": "Neuropathic mechanisms unlikely. Treat with standard analgesic approaches appropriate to pain severity and cause. Monitor for development of neuropathic features.", "neuropathic": "Neuropathic mechanisms likely. Initiate or optimize neuropathic pain treatment. Consider specialist referral if refractory. Address underlying cause if identifiable."}, "limitations": ["Requires clinical examination component (Part B) for full accuracy", "Mixed pain presentations may have both nociceptive and neuropathic components", "Does not identify specific neuropathic pain etiology", "Self-report section (Part A) can be used alone but with reduced accuracy"], "references": ["Bennett M. The LANSS Pain Scale: the Leeds assessment of neuropathic symptoms and signs. Pain. 2001;92(1-2):147-157.", "Bennett MI, Smith BH, Torrance N, Potter J. The S-LANSS score for identifying pain of predominantly neuropathic origin: validation for use in clinical and postal research. J Pain. 2005;6(3):149-158."]}'::jsonb)
