-- MADRS: 10 questions, 0 branch rule(s)
DO $$
DECLARE
  v_scale_id UUID;
BEGIN

  -- Scale
  INSERT INTO prs_scales (
    scale_code, name, short_name, description, category, version,
    recall_period, instructions, estimated_time, scoring_method,
    max_score, min_score, max_item_score, total_items, score_direction,
    cutoff_score, scoring_config, severity_bands, risk_rules, interpretation)
  VALUES (
    'MADRS', 'Montgomery-Åsberg Depression Rating Scale', 'MADRS',
    'A clinician-administered scale for measuring depression severity', NULL, '1.0',
    'Variable (typically past week)', 'The ratings should be based on a clinical interview moving from broadly phrased questions about symptoms to more detailed ones which allow a precise rating of severity. The rater must decide whether the rating lies on the defined scale steps (0, 2, 4, 6). It is important to remember that it is only rare occasions that a depressed patient is encountered who cannot be rated on the items in the scale. If definite answers cannot be elicited from the patients, all relevant clues as well as information from other sources should be used as a basis for the rating in line with customary clinical practice. This scale may be used for any time interval between ratings, be it weekly or otherwise, but this must be recorded.',
    NULL, 'sum',
    60.0, 0.0, 6.0,
    10.0, 'higher_worse',
    NULL,
    '{}'::jsonb, '[{"min": 0, "max": 6, "level": "minimal", "label": "Normal/Symptom Absent", "description": "No significant depressive symptoms"}, {"min": 7, "max": 19, "level": "mild", "label": "Mild Depression", "description": "Mild depressive symptoms"}, {"min": 20, "max": 34, "level": "moderate", "label": "Moderate Depression", "description": "Moderate depressive symptoms; treatment indicated"}, {"min": 35, "max": 60, "level": "severe", "label": "Severe Depression", "description": "Severe depressive symptoms; intensive treatment required"}]'::jsonb,
    '[{"questionIndex": 9, "operator": ">=", "threshold": 4, "type": "suicide_risk", "severity": "high", "message": "MADRS Suicidal Thoughts item score \u2265 4 indicates elevated suicide risk requiring immediate clinical attention"}, {"questionIndex": 9, "operator": ">=", "threshold": 2, "type": "suicide_ideation_present", "severity": "moderate", "message": "MADRS indicates presence of suicidal ideation"}]'::jsonb, '{"clinicalNotes": "The MADRS is designed to be sensitive to change during treatment and is widely used in antidepressant clinical trials. It is clinician-administered and should be based on a clinical interview. Ratings are on defined steps (0, 2, 4, 6).", "actions": {"minimal": "No treatment indicated for depression. Monitor as needed.", "mild": "Consider treatment based on clinical judgment; psychotherapy may be beneficial.", "moderate": "Treatment indicated; consider combination of psychotherapy and pharmacotherapy.", "severe": "Intensive treatment required; consider psychiatric referral and close monitoring."}, "responseDefinitions": {"response": "\u226550% reduction from baseline score", "remission": "Score \u2264 10"}, "references": ["Montgomery SA, \u00c5sberg M. A new depression scale designed to be sensitive to change. Br J Psychiatry. 1979;134:382-389."]}'::jsonb)
  ON CONFLICT (scale_code) DO UPDATE SET
    name = EXCLUDED.name, description = EXCLUDED.description,
    scoring_method = EXCLUDED.scoring_method, max_score = EXCLUDED.max_score,
    scoring_config = EXCLUDED.scoring_config, severity_bands = EXCLUDED.severity_bands,
    risk_rules = EXCLUDED.risk_rules, updated_at = NOW()
  RETURNING id INTO v_scale_id;

  -- Questions
