    NULL, NULL,
    '[{"value": 0, "label": "No sadness", "points": 0}, {"value": 2, "label": "Looks dispirited but does brighten up without difficulty.", "points": 2}, {"value": 4, "label": "Appears sad and unhappy most of the time.", "points": 4}, {"value": 6, "label": "Looks miserable all the time. Extremely despondent.", "points": 6}]'::jsonb, NULL,
