    left_anchor, right_anchor,
    options, instructions, hint, note, scoring_note,
    section_ref, subscale_ref, domain_ref, weight, multiplier, used_in_component)
  VALUES (
    v_scale_id, 1, 2.0, NULL,
    'Reported Sadness', 'Representing reports of depressed mood, regardless of whether it is reflected in appearance or not. Includes low spirits, despondency or feeling of being beyond help without hope. Rate according to intensity, duration and the extent to which the mood is reported to be influenced by events.', 'likert',
    TRUE, TRUE, TRUE, FALSE,
    FALSE, FALSE, FALSE,
    NULL, NULL,
    NULL, NULL, NULL,
    NULL, NULL,
    '[{"value": 0, "label": "Occasional sadness in keeping with the circumstances.", "points": 0}, {"value": 2, "label": "Sad or low but brightens up without difficulty.", "points": 2}, {"value": 4, "label": "Pervasive feelings of sadness or gloominess. The mood is still influenced by external circumstances.", "points": 4}, {"value": 6, "label": "Continuous or unvarying sadness, misery or despondency.", "points": 6}]'::jsonb, NULL,
    NULL, NULL, NULL,
    NULL, NULL, NULL,
