DO $$
DECLARE
  v_scale_id UUID;
BEGIN

  -- Scale
  INSERT INTO prs_scales (
    scale_code, name, short_name, description, category, version,
    recall_period, instructions, estimated_time, scoring_method,
    max_score, min_score, max_item_score, total_items, score_direction,
    cutoff_score, scoring_config, severity_bands, risk_rules, interpretation)
  VALUES (
    'MAS', 'Modified Ashworth Scale', 'MAS',
    'A clinical scale for grading spasticity and muscle tone. Measures resistance during passive soft-tissue stretching. Used to assess muscle hypertonia in patients with neurological conditions such as stroke, spinal cord injury, multiple sclerosis, and cerebral palsy.', 'motor-function', '1.0',
    'Current examination', 'Place the patient in a supine position. For muscles that primarily flex a joint, place the joint in maximal flexion and move to maximal extension over one second. For muscles that primarily extend a joint, place the joint in maximal extension and move to maximal flexion over one second. Score based on the resistance felt during passive movement.',
    '5-10 minutes per muscle group', 'single-selection',
    4.0, 0.0, NULL,
    1.0, 'higher_worse',
    NULL,
    '{}'::jsonb, '[{"id": "normal", "label": "Normal Tone", "min": 0, "max": 0, "color": "#22c55e", "description": "No increase in muscle tone."}, {"id": "mild", "label": "Mild Spasticity", "min": 1, "max": 1.5, "color": "#eab308", "description": "Slight increase in muscle tone with catch and/or minimal resistance."}, {"id": "moderate", "label": "Moderate Spasticity", "min": 2, "max": 2, "color": "#f97316", "description": "More marked increase in muscle tone but limb easily moved."}, {"id": "severe", "label": "Severe Spasticity", "min": 3, "max": 4, "color": "#dc2626", "description": "Considerable increase in tone; passive movement difficult or limb rigid."}]'::jsonb,
    '[]'::jsonb, '{"scoringMethod": "Single selection from 0 to 4 (with 1+ between 1 and 2). Score each muscle group separately.", "grades": {"0": "No increase in muscle tone", "1": "Slight increase - catch and release or minimal resistance at end ROM", "1+": "Slight increase - catch followed by minimal resistance through <50% ROM", "2": "More marked increase through most of ROM, but easily moved", "3": "Considerable increase, passive movement difficult", "4": "Rigid in flexion or extension"}, "clinicalUse": "Used to monitor spasticity changes over time, evaluate treatment effectiveness (botulinum toxin, baclofen, physical therapy), and guide rehabilitation planning.", "limitations": "Ordinal scale with unequal intervals. Inter-rater reliability can vary. Does not distinguish between neural and non-neural components of resistance."}'::jsonb)
  ON CONFLICT (scale_code) DO UPDATE SET
    name = EXCLUDED.name, description = EXCLUDED.description,
    scoring_method = EXCLUDED.scoring_method, max_score = EXCLUDED.max_score,
    scoring_config = EXCLUDED.scoring_config, severity_bands = EXCLUDED.severity_bands,
    risk_rules = EXCLUDED.risk_rules, updated_at = NOW()
  RETURNING id INTO v_scale_id;

  -- Questions
  INSERT INTO prs_questions (
    scale_id, question_index, question_number, original_id,
    label, question_text, question_type,
    is_required, scored_in_total, include_in_score, supplementary,
    is_critical, is_risk_item, reversed,
    min_value, max_value, step_value, unit, placeholder,
    left_anchor, right_anchor,
    options, instructions, hint, note, scoring_note,
    section_ref, subscale_ref, domain_ref, weight, multiplier, used_in_component)
  VALUES (
    v_scale_id, 0, 1.0, 'MAS_1',
    NULL, 'Rate the muscle tone/spasticity during passive movement:', 'single-selection',
    TRUE, TRUE, TRUE, FALSE,
    FALSE, FALSE, FALSE,
    NULL, NULL,
    NULL, NULL, NULL,
    NULL, NULL,
    '[{"value": 0, "label": "0 - No increase in muscle tone", "points": 0, "description": "No increase in muscle tone"}, {"value": 1, "label": "1 - Slight increase in muscle tone, manifested by a catch and release or by minimal resistance at the end of ROM", "points": 1, "description": "Slight increase in muscle tone, manifested by a catch and release or by minimal resistance at the end of the range of motion when the affected part(s) is moved in flexion or extension"}, {"value": 1.5, "label": "1+ - Slight increase in muscle tone, manifested by a catch, followed by minimal resistance throughout less than half of ROM", "points": 1.5, "description": "Slight increase in muscle tone, manifested by a catch, followed by minimal resistance throughout the remainder (less than half) of the ROM"}, {"value": 2, "label": "2 - More marked increase in muscle tone through most of ROM, but affected part(s) easily moved", "points": 2, "description": "More marked increase in muscle tone through most of the ROM, but affected part(s) easily moved"}, {"value": 3, "label": "3 - Considerable increase in muscle tone, passive movement difficult", "points": 3, "description": "Considerable increase in muscle tone, passive movement difficult"}, {"value": 4, "label": "4 - Affected part(s) rigid in flexion or extension", "points": 4, "description": "Affected part(s) rigid in flexion or extension"}]'::jsonb, NULL,
    NULL, NULL, NULL,
    NULL, NULL, NULL,
    NULL, NULL, NULL)
  ON CONFLICT (scale_id, question_index) DO UPDATE SET
    question_text = EXCLUDED.question_text,
    options = EXCLUDED.options,
    question_type = EXCLUDED.question_type;

END $$;

