    '5-10 minutes', 'sum',
    84.0, 0.0, NULL,
    21.0, 'higher_worse',
    NULL,
    '{"subscales": [{"id": "physical", "name": "Physical Subscale", "items": ["MFIS_4", "MFIS_6", "MFIS_7", "MFIS_10", "MFIS_13", "MFIS_14", "MFIS_17", "MFIS_20", "MFIS_21"], "minScore": 0, "maxScore": 36, "description": "Assesses fatigue impact on physical functioning (9 items)"}, {"id": "cognitive", "name": "Cognitive Subscale", "items": ["MFIS_1", "MFIS_2", "MFIS_3", "MFIS_5", "MFIS_11", "MFIS_12", "MFIS_15", "MFIS_16", "MFIS_18", "MFIS_19"], "minScore": 0, "maxScore": 40, "description": "Assesses fatigue impact on cognitive functioning (10 items)"}, {"id": "psychosocial", "name": "Psychosocial Subscale", "items": ["MFIS_8", "MFIS_9"], "minScore": 0, "maxScore": 8, "description": "Assesses fatigue impact on psychosocial functioning (2 items)"}]}'::jsonb, '[{"id": "none-minimal", "label": "No/Minimal Fatigue Impact", "min": 0, "max": 20, "color": "#22c55e", "description": "Little to no impact of fatigue on daily functioning."}, {"id": "mild", "label": "Mild Fatigue Impact", "min": 21, "max": 40, "color": "#eab308", "description": "Mild impact of fatigue on activities."}, {"id": "moderate", "label": "Moderate Fatigue Impact", "min": 41, "max": 60, "color": "#f97316", "description": "Moderate impact of fatigue on daily functioning."}, {"id": "severe", "label": "Severe Fatigue Impact", "min": 61, "max": 84, "color": "#dc2626", "description": "Severe impact of fatigue on physical, cognitive, and psychosocial functioning."}]'::jsonb,
    '[]'::jsonb, '{"scoringMethod": "Sum all 21 item scores for total. Subscale scores computed by summing relevant items. Higher scores indicate greater fatigue impact.", "subscaleScoring": {"physical": "Items 4+6+7+10+13+14+17+20+21 (range 0-36)", "cognitive": "Items 1+2+3+5+11+12+15+16+18+19 (range 0-40)", "psychosocial": "Items 8+9 (range 0-8)"}, "totalRange": "0-84", "clinicalUse": "Widely used in MS research and clinical practice to assess fatigue impact. Also applicable to other chronic fatigue conditions."}'::jsonb)
