DO $$
DECLARE
  v_scale_id UUID;
BEGIN

  -- Scale
  INSERT INTO prs_scales (
    scale_code, name, short_name, description, category, version,
    recall_period, instructions, estimated_time, scoring_method,
    max_score, min_score, max_item_score, total_items, score_direction,
    cutoff_score, scoring_config, severity_bands, risk_rules, interpretation)
  VALUES (
    'MIDAS', 'Migraine Disability Assessment', 'MIDAS',
    'A validated questionnaire to assess headache-related disability over the past 3 months. Measures the impact of headaches on work, household activities, and social/leisure activities to help guide treatment decisions.', 'headache', '1.0',
    'Over the last 3 months', 'Please answer the following questions about ALL your headaches you have had over the last 3 months. Write your answer in the box next to each question. Write zero if you did not do the activity in the last 3 months.',
    '5 minutes', 'sum-numeric',
    NULL, 0.0, NULL,
