-- PFS-16: 16 questions, 0 branch rule(s)
DO $$
DECLARE
  v_scale_id UUID;
BEGIN

  -- Scale
  INSERT INTO prs_scales (
    scale_code, name, short_name, description, category, version,
    recall_period, instructions, estimated_time, scoring_method,
    max_score, min_score, max_item_score, total_items, score_direction,
    cutoff_score, scoring_config, severity_bands, risk_rules, interpretation)
  VALUES (
    'PFS-16', 'Parkinson''s Disease Fatigue Scale', 'PFS-16',
    'A 16-item scale specifically designed to assess fatigue and its impact in patients with Parkinson''s disease. Measures both the presence and severity of fatigue experienced over the past two weeks.', 'fatigue', '1.0',
    'Over the past two weeks', 'Printed below are a series of statements about fatigue and the impact that it can have. How well do the statements describe your own feelings and experiences over the past two weeks? Read each item and decide how much you agree or disagree with it. Tick only one box for each item and try not to miss any out.',
    '5-10 minutes', 'pfs-dual',
    80.0, 0.0, NULL,
    16.0, 'higher_worse',
    NULL,
    '{}'::jsonb, '[{"id": "no-significant-fatigue", "label": "No Significant Fatigue", "min": 0, "max": 7, "color": "#22c55e", "description": "Binary score <8: No significant fatigue present.", "scoringMethod": "binary"}, {"id": "significant-fatigue", "label": "Significant Fatigue", "min": 8, "max": 16, "color": "#dc2626", "description": "Binary score \u22658: Significant fatigue is present.", "scoringMethod": "binary"}]'::jsonb,
    '[]'::jsonb, '{"scoringMethod1": {"method": "Sum all 16 items using Likert values (1-5). Range: 16-80.", "interpretation": "Higher scores indicate more severe fatigue."}, "scoringMethod2": {"method": "Binary scoring: Strongly disagree/Disagree/Neutral = 0, Agree/Strongly agree = 1. Range: 0-16.", "cutoff": "A score of \u22658 indicates the presence of significant fatigue.", "interpretation": "Used for identifying clinically significant fatigue in Parkinson''s disease."}, "clinicalUse": "Specifically designed for Parkinson''s disease patients. Can be used to monitor fatigue over time and evaluate treatment response."}'::jsonb)
  ON CONFLICT (scale_code) DO UPDATE SET
    name = EXCLUDED.name, description = EXCLUDED.description,
    scoring_method = EXCLUDED.scoring_method, max_score = EXCLUDED.max_score,
    scoring_config = EXCLUDED.scoring_config, severity_bands = EXCLUDED.severity_bands,
    risk_rules = EXCLUDED.risk_rules, updated_at = NOW()
  RETURNING id INTO v_scale_id;

  -- Questions
  INSERT INTO prs_questions (
    scale_id, question_index, question_number, original_id,
    label, question_text, question_type,
    is_required, scored_in_total, include_in_score, supplementary,
    is_critical, is_risk_item, reversed,
    min_value, max_value, step_value, unit, placeholder,
    left_anchor, right_anchor,
    options, instructions, hint, note, scoring_note,
    section_ref, subscale_ref, domain_ref, weight, multiplier, used_in_component)
  VALUES (
    v_scale_id, 0, 1.0, 'PFS_1',
    NULL, 'I have to rest during the day', 'likert',
    TRUE, TRUE, TRUE, FALSE,
    FALSE, FALSE, FALSE,
    NULL, NULL,
