10, 11, 12, 13], "maxScore": 3, "scoringRules": {"type": "sum-then-categorize", "maxRawSum": 27, "ranges": [{"min": 0, "max": 0, "score": 0}, {"min": 1, "max": 9, "score": 1}, {"min": 10, "max": 18, "score": 2}, {"min": 19, "max": 27, "score": 3}]}}, {"id": 6, "name": "Use of Sleep Medication", "description": "Frequency of sleep medication use", "scoring": "Q6 score directly", "questionIndices": [14], "maxScore": 3}, {"id": 7, "name": "Daytime Dysfunction", "description": "Problems with daytime alertness and motivation", "scoring": "Q7 + Q8, then categorized (0=0; 1-2=1; 3-4=2; 5-6=3)", "questionIndices": [15, 16], "maxScore": 3, "scoringRules": {"type": "sum-then-categorize", "maxRawSum": 6, "ranges": [{"min": 0, "max": 0, "score": 0}, {"min": 1, "max": 2, "score": 1}, {"min": 3, "max": 4, "score": 2}, {"min": 5, "max": 6, "score": 3}]}}]}'::jsonb, '[{"min": 0, "max": 5, "level": "good", "label": "Good Sleep Quality", "description": "No significant sleep difficulties"}, {"min": 6, "max": 10, "level": "moderate", "label": "Poor Sleep Quality", "description": "Moderate sleep difficulties; further evaluation recommended"}, {"min": 11, "max": 15, "level": "poor", "label": "Very Poor Sleep Quality", "description": "Significant sleep difficulties; clinical intervention recommended"}, {"min": 16, "max": 21, "level": "severe", "label": "Severe Sleep Difficulties", "description": "Severe sleep impairment; comprehensive sleep evaluation and treatment indicated"}]'::jsonb,
