  VALUES (
    'Pain-Rating-Scale', 'Pain Rating Scale', 'PRS',
    'A comprehensive pain assessment using numeric rating scales to evaluate pain intensity, interference with daily activities, and pain-related distress.', 'pain', '1.0',
    'Current/Past 24 hours', 'Please rate your pain by selecting the number that best describes your experience. 0 means no pain and 10 means the worst pain imaginable.',
    '2-3 minutes', 'sum',
    60.0, 0.0, 10.0,
    6.0, 'higher_worse',
