    '{}'::jsonb, '[{"id": "no-pain", "label": "No Pain", "min": 0, "max": 0, "color": "#22c55e", "description": "No pain reported."}, {"id": "mild", "label": "Mild Pain", "min": 1, "max": 18, "color": "#84cc16", "description": "Mild pain with minimal impact on daily functioning."}, {"id": "moderate", "label": "Moderate Pain", "min": 19, "max": 36, "color": "#eab308", "description": "Moderate pain that may interfere with some daily activities."}, {"id": "severe", "label": "Severe Pain", "min": 37, "max": 54, "color": "#f97316", "description": "Severe pain significantly impacting daily functioning and quality of life."}, {"id": "extreme", "label": "Extreme Pain", "min": 55, "max": 60, "color": "#ef4444", "description": "Extreme, debilitating pain requiring immediate clinical attention."}]'::jsonb,
    '[]'::jsonb, '{"domains": {"intensity": "Questions 1-3 assess pain intensity (current, average, worst)", "interference": "Questions 4-5 measure how pain interferes with daily life", "distress": "Question 6 captures emotional impact of pain"}, "clinicalNotes": "Individual item scores of 7 or higher warrant clinical attention. Consider the pattern across domains - high intensity with low interference may indicate good coping, while the reverse may suggest need for pain management support."}'::jsonb)
