    max_score, min_score, max_item_score, total_items, score_direction,
    cutoff_score, scoring_config, severity_bands, risk_rules, interpretation)
  VALUES (
    'SLEEP-50', 'SLEEP-50 Questionnaire', 'SLEEP-50',
    'A comprehensive 50-item screening questionnaire for sleep disorders. Assesses multiple sleep disorder categories including sleep apnea, insomnia, narcolepsy, restless legs syndrome, circadian rhythm disorders, parasomnias, nightmares, and daytime functioning.', 'sleep', '1.0',
    'During the past 4 weeks', 'Please respond to what extent a statement has been applicable to you during the past 4 weeks. Score each item on a 4-point scale: 1 (not at all), 2 (somewhat), 3 (rather much), 4 (very much).',
    '10-15 minutes', 'sum-subscales',
    200.0, 0.0, NULL,
    50.0, 'higher_worse',
    NULL,
    '{"subscales": [{"id": "sleep-apnea", "name": "Sleep Apnea", "section": 1, "items": ["SLEEP50_1", "SLEEP50_2", "SLEEP50_3", "SLEEP50_4", "SLEEP50_5", "SLEEP50_6", "SLEEP50_7", "SLEEP50_8"], "minScore": 8, "maxScore": 32, "description": "Screens for obstructive sleep apnea symptoms"}, {"id": "insomnia", "name": "Insomnia", "section": 2, "items": ["SLEEP50_9", "SLEEP50_10", "SLEEP50_11", "SLEEP50_12", "SLEEP50_13", "SLEEP50_14", "SLEEP50_15", "SLEEP50_16"], "minScore": 8, "maxScore": 32, "description": "Screens for insomnia symptoms including sleep onset, maintenance, and early awakening"}, {"id": "narcolepsy", "name": "Narcolepsy", "section": 3, "items": ["SLEEP50_17", "SLEEP50_18", "SLEEP50_19", "SLEEP50_20", "SLEEP50_21"], "minScore": 5, "maxScore": 20, "description": "Screens for narcolepsy symptoms including hypnagogic hallucinations, sleep attacks, cataplexy, and sleep paralysis"}, {"id": "restless-legs", "name": "Restless Legs Syndrome / PLMD", "section": 4, "items": ["SLEEP50_22", "SLEEP50_23", "SLEEP50_24", "SLEEP50_25"], "minScore": 4, "maxScore": 16, "description": "Screens for restless legs syndrome and periodic limb movement disorder"}, {"id": "circadian-rhythm", "name": "Circadian Rhythm Disorder", "section": 5, "items": ["SLEEP50_26", "SLEEP50_27", "SLEEP50_28"], "minScore": 3, "maxScore": 12, "description": "Screens for circadian rhythm sleep disorders including shift work"}, {"id": "sleepwalking", "name": "Sleepwalking / Parasomnia", "section": 6, "items": ["SLEEP50_29", "SLEEP50_30", "SLEEP50_31"], "minScore": 3, "maxScore": 12, "description": "Screens for sleepwalking and other NREM parasomnias"}, {"id": "nightmares", "name": "Nightmares / REM Behavior", "section": 7, "items": ["SLEEP50_32", "SLEEP50_33", "SLEEP50_34", "SLEEP50_35", "SLEEP50_36"], "minScore": 5, "maxScore": 20, "description": "Screens for nightmare disorder and REM-related parasomnias"}, {"id": "sleep-hygiene", "name": "Factors Influencing Sleep", "section": 8, "items": ["SLEEP50_37", "SLEEP50_38", "SLEEP50_39", "SLEEP50_40", "SLEEP50_41", "SLEEP50_42", "SLEEP50_43"], "minScore": 7, "maxScore": 28, "description": "Assesses environmental, substance, and mood factors affecting sleep"}, {"id": "daytime-functioning", "name": "Impact of Sleep / Daytime Functioning", "section": 9, "items": ["SLEEP50_44", "SLEEP50_45", "SLEEP50_46", "SLEEP50_47", "SLEEP50_48", "SLEEP50_49", "SLEEP50_50"], "minScore": 7, "maxScore": 28, "description": "Assesses daytime consequences of sleep problems"}]}'::jsonb, '[{"id": "minimal", "label": "Minimal Sleep Problems", "min": 50, "max": 87, "color": "#22c55e", "description": "Few or no significant sleep problems indicated."}, {"id": "mild", "label": "Mild Sleep Problems", "min": 88, "max": 125, "color": "#eab308", "description": "Some sleep difficulties present."}, {"id": "moderate", "label": "Moderate Sleep Problems", "min": 126, "max": 163, "color": "#f97316", "description": "Moderate sleep difficulties requiring attention."}, {"id": "severe", "label": "Severe Sleep Problems", "min": 164, "max": 200, "color": "#dc2626", "description": "Significant sleep problems requiring clinical evaluation."}]'::jsonb,
