  VALUES (
    'SNAP-IV', 'SNAP-IV 26-Item Teacher and Parent Rating Scale', 'SNAP-IV-26',
    'An abbreviated version of the Swanson, Nolan, and Pelham (SNAP) Questionnaire used to assess ADHD and Oppositional Defiant Disorder symptoms based on DSM-IV criteria. Includes subscales for Inattention, Hyperactivity/Impulsivity, and Opposition/Defiance.', 'adhd', '1.0',
    'Current behavior', 'For each item, check the column which best describes this child/adolescent. Rate how often each behavior occurs.',
    '10 minutes', 'sum-subscales',
    78.0, 0.0, NULL,
    26.0, 'higher_worse',
    NULL,
    '{"subscales": [{"id": "inattention", "name": "Inattention", "items": ["SNAP_1", "SNAP_2", "SNAP_3", "SNAP_4", "SNAP_5", "SNAP_6", "SNAP_7", "SNAP_8", "SNAP_9"], "minScore": 0, "maxScore": 27, "dsmCriteria": "ADHD Inattentive symptoms", "severityBands": [{"label": "Not clinically significant", "min": 0, "max": 12}, {"label": "Mild symptoms", "min": 13, "max": 17}, {"label": "Moderate symptoms", "min": 18, "max": 22}, {"label": "Severe symptoms", "min": 23, "max": 27}], "targetScore": "<13"}, {"id": "hyperactivity-impulsivity", "name": "Hyperactivity/Impulsivity", "items": ["SNAP_10", "SNAP_11", "SNAP_12", "SNAP_13", "SNAP_14", "SNAP_15", "SNAP_16", "SNAP_17", "SNAP_18"], "minScore": 0, "maxScore": 27, "dsmCriteria": "ADHD Hyperactive-Impulsive symptoms", "severityBands": [{"label": "Not clinically significant", "min": 0, "max": 12}, {"label": "Mild symptoms", "min": 13, "max": 17}, {"label": "Moderate symptoms", "min": 18, "max": 22}, {"label": "Severe symptoms", "min": 23, "max": 27}], "targetScore": "<13"}, {"id": "opposition-defiance", "name": "Opposition/Defiance", "items": ["SNAP_19", "SNAP_20", "SNAP_21", "SNAP_22", "SNAP_23", "SNAP_24", "SNAP_25", "SNAP_26"], "minScore": 0, "maxScore": 24, "dsmCriteria": "Oppositional Defiant Disorder symptoms", "severityBands": [{"label": "Not clinically significant", "min": 0, "max": 7}, {"label": "Mild symptoms", "min": 8, "max": 13}, {"label": "Moderate symptoms", "min": 14, "max": 18}, {"label": "Severe symptoms", "min": 19, "max": 24}], "targetScore": "<8"}]}'::jsonb, '[{"id": "not-significant", "label": "Not Clinically Significant", "min": 0, "max": 19, "color": "#22c55e", "description": "Symptoms below clinical threshold."}, {"id": "mild", "label": "Mild Symptoms", "min": 20, "max": 39, "color": "#eab308", "description": "Mild symptom severity present."}, {"id": "moderate", "label": "Moderate Symptoms", "min": 40, "max": 58, "color": "#f97316", "description": "Moderate symptom severity."}, {"id": "severe", "label": "Severe Symptoms", "min": 59, "max": 78, "color": "#dc2626", "description": "Severe symptom severity requiring clinical attention."}]'::jsonb,
