    'A patient-reported outcome measure designed to assess health-related quality of life specific to stroke survivors. Covers 12 domains including energy, family roles, language, mobility, mood, personality, self-care, social roles, thinking, upper extremity function, vision, and work/productivity.', 'quality-of-life', '1.0',
    'Past week', 'Please answer each question based on how you have been doing in the past week. Score each item on a 5-point scale where higher scores indicate better functioning.',
    '10-15 minutes', 'sum-subscales',
    245.0, 49.0, NULL,
    49.0, 'higher_worse',
    NULL,
    '{"subscales": [{"id": "energy", "name": "Energy", "items": ["SSQOL_E1", "SSQOL_E2", "SSQOL_E3"], "minScore": 3, "maxScore": 15, "description": "Fatigue and energy levels"}, {"id": "family-roles", "name": "Family Roles", "items": ["SSQOL_FR1", "SSQOL_FR2", "SSQOL_FR3"], "minScore": 3, "maxScore": 15, "description": "Participation in family activities and perceived burden"}, {"id": "language", "name": "Language", "items": ["SSQOL_L1", "SSQOL_L2", "SSQOL_L3", "SSQOL_L4", "SSQOL_L5"], "minScore": 5, "maxScore": 25, "description": "Communication and speech difficulties"}, {"id": "mobility", "name": "Mobility", "items": ["SSQOL_M1", "SSQOL_M2", "SSQOL_M3", "SSQOL_M4", "SSQOL_M5", "SSQOL_M6"], "minScore": 6, "maxScore": 30, "description": "Walking, balance, transfers, and physical movement"}, {"id": "mood", "name": "Mood", "items": ["SSQOL_MO1", "SSQOL_MO2", "SSQOL_MO3", "SSQOL_MO4", "SSQOL_MO5"], "minScore": 5, "maxScore": 25, "description": "Emotional wellbeing and depressive symptoms"}, {"id": "personality", "name": "Personality", "items": ["SSQOL_P1", "SSQOL_P2", "SSQOL_P3"], "minScore": 3, "maxScore": 15, "description": "Changes in temperament and personality"}, {"id": "self-care", "name": "Self Care", "items": ["SSQOL_SC1", "SSQOL_SC2", "SSQOL_SC3", "SSQOL_SC4", "SSQOL_SC5"], "minScore": 5, "maxScore": 25, "description": "Independence in activities of daily living"}, {"id": "social-roles", "name": "Social Roles", "items": ["SSQOL_SR1", "SSQOL_SR2", "SSQOL_SR3", "SSQOL_SR4", "SSQOL_SR5"], "minScore": 5, "maxScore": 25, "description": "Social participation and relationships"}, {"id": "thinking", "name": "Thinking", "items": ["SSQOL_T1", "SSQOL_T2", "SSQOL_T3"], "minScore": 3, "maxScore": 15, "description": "Concentration and memory"}, {"id": "upper-extremity", "name": "Upper Extremity Function", "items": ["SSQOL_UE1", "SSQOL_UE2", "SSQOL_UE3", "SSQOL_UE4", "SSQOL_UE5"], "minScore": 5, "maxScore": 25, "description": "Fine motor skills and arm/hand function"}, {"id"