    cutoff_score, scoring_config, severity_bands, risk_rules, interpretation)
  VALUES (
    'painDETECT', 'painDETECT Questionnaire', 'painDETECT',
    'A validated screening tool for identifying neuropathic pain components in patients with chronic pain. Assesses pain intensity, sensory symptoms, pain pattern, and radiation to determine the likelihood of neuropathic pain.', 'pain', '1.0',
    'Current and past 4 weeks', 'Mark your main area of pain. Answer questions about pain intensity and sensory symptoms. Select the pattern that best describes your pain and indicate if pain radiates.',
    '5-10 minutes', 'paindetect',
    38.0, 0.0, NULL,
    12.0, 'higher_worse',
    NULL,
    '{}'::jsonb, '[{"id": "nociceptive", "label": "Nociceptive Pain (Neuropathic Unlikely)", "min": -1, "max": 12, "color": "#22c55e", "description": "A neuropathic pain component is unlikely (<15% probability)."}, {"id": "unclear", "label": "Unclear/Ambiguous", "min": 13, "max": 18, "color": "#eab308", "description": "Result is ambiguous; however, a neuropathic pain component can be present."}, {"id": "neuropathic", "label": "Neuropathic Pain Likely", "min": 19, "max": 38, "color": "#dc2626", "description": "A neuropathic pain component is likely (>90% probability)."}]'::jsonb,
    '[]'::jsonb, '{"scoringMethod": "Sum of 7 sensory symptom scores (0-35) + pain pattern score (-1, 0, or +1) + radiation score (0 or +2). Final score range: -1 to 38.", "components": {"sensorySymptoms": "Items 4-10: Sum of points (range 0-35)", "painPattern": "Item 11: Adds -1, 0, or +1 based on pattern selected", "radiation": "Item 12: Adds +2 if pain radiates"}, "cutoffs": {"nociceptive": "\u226412: Neuropathic component unlikely (<15%)", "unclear": "13-18: Ambiguous result", "neuropathic": "\u226519: Neuropathic component likely (>90%)"}, "clinicalNote": "This screening tool does not replace medical diagnostics. It is used for screening the presence of a neuropathic pain component.", "painIntensityScores": "NRS items 1-3 provide clinical information about pain intensity but are not included in the painDETECT score."}'::jsonb)
