-- STEP 29: SEED DATA — prs_disease_scales
-- Maps each disease to its ordered scale battery (131 rows total)
-- ============================================================

-- Depression/Anxiety (7 scales)
INSERT INTO prs_disease_scales (disease_id, scale_id, display_order)
SELECT d.id, s.id, v.ord
FROM prs_diseases d, prs_scales s,
  (VALUES
    ('EQ-5D-5L', 0),
    ('BPQ-Short-Form', 1),
    ('PHQ-9', 2),
    ('DASS-21', 3),
    ('GAD-7', 4),
    ('MADRS', 5),
    ('PSQI', 6)
  ) AS v(sc, ord)
WHERE d.disease_code = 'depression-anxiety' AND s.scale_code = v.sc
ON CONFLICT (disease_id, scale_id) DO UPDATE SET display_order = EXCLUDED.display_order;

-- Chronic Pain (9 scales)
INSERT INTO prs_disease_scales (disease_id, scale_id, display_order)
SELECT d.id, s.id, v.ord
FROM prs_diseases d, prs_scales s,
  (VALUES
    ('EQ-5D-5L', 0),
    ('BPQ-Short-Form', 1),
    ('PHQ-9', 2),
    ('DASS-21', 3),
    ('GAD-7', 4),
    ('PSQI', 5),
    ('EDSS', 6),
    ('Pain-Rating-Scale', 7),
    ('LANSS', 8)
  ) AS v(sc, ord)
WHERE d.disease_code = 'chronic-pain' AND s.scale_code = v.sc
ON CONFLICT (disease_id, scale_id) DO UPDATE SET display_order = EXCLUDED.display_order;

-- Fibromyalgia (11 scales)
INSERT INTO prs_disease_scales (disease_id, scale_id, display_order)
SELECT d.id, s.id, v.ord
FROM prs_diseases d, prs_scales s,
  (VALUES
    ('EQ-5D-5L', 0),
    ('BPQ-Short-Form', 1),
