-- ============================================================
-- VERIFICATION QUERY — run after setup to confirm all tables
-- ============================================================
SELECT
  schemaname,
  tablename,
  rowsecurity AS rls_enabled
FROM pg_tables
WHERE schemaname = 'public'
  AND tablename IN (
    'profiles', 'doctors', 'patients', 'sessions',
    'doctor_patient_allocations',
    'prs_diseases', 'prs_scales',
    'prs_questions', 'prs_question_branches', 'prs_disease_scales',
    'assessment_permissions', 'assessment_sessions',
    'assessment_responses', 'scale_scores',
    'assessment_scores', 'notifications', 'audit_logs'
  )
ORDER BY tablename;

-- Row counts for seeded reference data
SELECT 'prs_diseases'          AS table_name, COUNT(*) AS rows FROM prs_diseases
UNION ALL
SELECT 'prs_scales',             COUNT(*) FROM prs_scales
UNION ALL
SELECT 'prs_questions',          COUNT(*) FROM prs_questions
UNION ALL
SELECT 'prs_question_branches',  COUNT(*) FROM prs_question_branches
UNION ALL
SELECT 'prs_disease_scales',     COUNT(*) FROM prs_disease_scales
ORDER BY table_name;

-- Expected:
--   prs_diseases            → 16
--   prs_scales              → 47
--   prs_questions           → 641
--   prs_question_branches   → 27  (AUDIT:1, COMPASS-31:19, GAD-7:1, IBS-SSS:2, SLEEP-50:4)
--   prs_disease_scales      → 131






-- Grant service_role access to the public schema and all tables
GRANT USAGE ON SCHEMA public TO service_role;
GRANT ALL ON ALL TABLES IN SCHEMA public TO service_role;
GRANT ALL ON ALL SEQUENCES IN SCHEMA public TO service_role;
GRANT ALL ON ALL FUNCTIONS IN SCHEMA public TO service_role;

-- Also ensure future tables get the same grants
ALTER DEFAULT PRIVILEGES IN SCHEMA public GRANT ALL ON TABLES TO service_role;
ALTER DEFAULT PRIVILEGES IN SCHEMA public GRANT ALL ON SEQUENCES TO service_role;
